FUNCTION UnionDecider(L1, L2, w):
  // L1 and L2 are recursive languages
  // Returns ACCEPT if w ∈ L1 ∪ L2, REJECT otherwise

  // Since L1 and L2 are recursive, we have deciders D1 and D2
  result1 = DeciderL1(w)  // Always halts
  result2 = DeciderL2(w)  // Always halts

  IF result1 = ACCEPT OR result2 = ACCEPT:
    RETURN ACCEPT
  ELSE:
    RETURN REJECT

// This always halts because both deciders halt
// Therefore L1 ∪ L2 is recursive (closed under union)

FUNCTION EnumerateR.E.(TM M):
  // Enumerates all strings accepted by TM M
  // A language is r.e. iff it can be enumerated

  n = 1
  WHILE true:
    // Try all strings of length up to n
    FOR each string w of length ≤ n:
      // Run M on w with time limit
      IF SimulateWithTimeout(M, w, n steps) = ACCEPT:
        OUTPUT w  // String accepted within n steps
    n = n + 1

// This eventually outputs every string in L(M)
// May run forever but outputs correct strings
// Characterizes r.e. languages
